import React, { useState, useEffect } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [filter, setFilter] = useState('');
    const [sortField, setSortField] = useState('name');
    const [sortDirection, setSortDirection] = useState('asc');

    // Sort function
    const sortRecords = (field) => {
        const sorted = [...records];
        sorted.sort((a, b) => {
            if (a[field] < b[field]) return sortDirection === 'asc' ? -1 : 1;
            if (a[field] > b[field]) return sortDirection === 'asc' ? 1 : -1;
            return 0;
        });
        setRecords(sorted);
    };

    // Filter function
    const filterRecords = (value) => {
        const filtered = [...records];
        filtered.filter(record => {
            const match = record.name.toLowerCase().includes(value.toLowerCase());
            return match;
        });
        setRecords(filtered);
    };

    // Handle input change
    const handleInputChange = (e) => {
        setFilter(e.target.value);
    };

    // Handle sort change
    const handleSortChange = (e) => {
        setSortField(e.target.value);
        setSortDirection(e.target.checked ? 'asc' : 'desc');
        sortRecords(e.target.value);
    };

    return (
        <div>
            <div>
                <input
                    type="text"
                    placeholder="Filter by name..."
                    value={filter}
                    onChange={handleInputChange}
                />
                <select value={sortField} onChange={handleSortChange}>
                    <option value="name">name</option>
                    <option value="id">id</option>
                    <option value="age">age</option>
                </select>
                <label>
                    Sort Direction:
                    <input
                        type="checkbox"
                        checked={sortDirection === 'asc'}
                        onChange={() => setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc')}
                    />
                </label>
